from __future__ import annotations
from dataclasses import dataclass, field
from enum import Enum
from typing import Any, Optional


class Speaker(Enum):
    USER = "user"
    AI   = "ai"
    SYSTEM = "system"


class BranchOutcome(Enum):
    CONTINUE   = "continue"       # advance to next node
    RETRY      = "retry"          # re-prompt for same slot
    FALLBACK   = "fallback"       # escalate / exit
    LOOP_BACK  = "loop_back"      # correct an earlier slot
    TERMINAL   = "terminal"       # conversation ends


@dataclass
class SlotState:
    """Snapshot of all slot values after a turn."""
    values: dict[str, Any]
    newly_filled: list[str] = field(default_factory=list)
    retry_counts: dict[str, int] = field(default_factory=dict)

    @property
    def unfilled_required(self) -> list[str]:
        return [k for k, v in self.values.items() if v is None]

    def is_complete(self, required_slots: list[str]) -> bool:
        return all(self.values.get(s) is not None for s in required_slots)


@dataclass
class ScriptTurn:
    turn_number: int
    speaker: Speaker
    utterance: str
    intent: Optional[str] = None
    slot_state: Optional[SlotState] = None
    branch: BranchOutcome = BranchOutcome.CONTINUE
    next_node: Optional[str] = None    # wireframe node id
    action: Optional[str] = None      # system action taken, if any


@dataclass
class ConversationScript:
    script_id: str
    flow_id: str           # wireframe node graph id this script exercises
    persona_id: str
    path_label: str        # e.g. "happy_path", "retry_destination", "fallback"
    required_slots: list[str]
    turns: list[ScriptTurn] = field(default_factory=list)

    def is_complete(self) -> bool:
        return any(t.branch == BranchOutcome.TERMINAL for t in self.turns)

    def slot_coverage(self) -> float:
        """Fraction of required slots filled before terminal turn."""
        filled: set[str] = set()
        for turn in self.turns:
            if turn.slot_state:
                filled.update(turn.slot_state.newly_filled)
            if turn.branch == BranchOutcome.TERMINAL:
                break
        return len(filled & set(self.required_slots)) / len(self.required_slots)

    def turn_count(self) -> int:
        return len(self.turns)

    def max_retry_count(self) -> int:
        """Highest retry count observed for any slot across all turns."""
        if not self.turns:
            return 0
        max_r = 0
        for turn in self.turns:
            if turn.slot_state:
                max_r = max(max_r, max(turn.slot_state.retry_counts.values(), default=0))
        return max_r

from dataclasses import dataclass, field


@dataclass
class SlotDependency:
    slot: str
    depends_on: list[str]   # must be filled before this slot is asked
    skip_if: str = ""       # condition under which this slot is skipped entirely

    def is_unlocked(self, slot_state: SlotState) -> bool:
        return all(slot_state.values.get(dep) is not None for dep in self.depends_on)


BOOKING_SLOT_GRAPH: list[SlotDependency] = [
    SlotDependency("destination",     depends_on=[]),
    SlotDependency("depart_date",     depends_on=["destination"]),
    SlotDependency("return_date",     depends_on=["depart_date"]),
    SlotDependency("cabin_class",     depends_on=["destination"], skip_if="budget_mode==True"),
    SlotDependency("seat_preference", depends_on=["cabin_class"]),
    SlotDependency("meal_preference", depends_on=["cabin_class"], skip_if="flight_under_2h"),
]


def next_slot_to_fill(
    slot_graph: list[SlotDependency],
    slot_state: SlotState,
) -> str | None:
    """Returns the next unfilled slot whose dependencies are all satisfied."""
    for dep in slot_graph:
        if slot_state.values.get(dep.slot) is None and dep.is_unlocked(slot_state):
            return dep.slot
    return None   # all slots filled or blocked by unsatisfied dependencies
